// frontend/src/components/Dashboard/StatsCards.js
import React from 'react';
import {
  Grid,
  Card,
  CardContent,
  Typography,
  Box,
  Skeleton,
  useTheme
} from '@mui/material';
import {
  TrendingUp,
  TrendingDown,
  AccountBalance,
  ShowChart,
  Timeline,
  Percent
} from '@mui/icons-material';

const StatsCards = ({ stats, loading, hideValues = false }) => {
  const theme = useTheme();

  const formatCurrency = (value) => {
    if (hideValues) return '$***';
    if (value === null || value === undefined) return '$0.00';
    const numValue = parseFloat(value);
    // Para valores muito pequenos (< 0.01), usar mais casas decimais
    if (Math.abs(numValue) < 0.01 && numValue !== 0) {
      return `$${numValue.toFixed(6)}`;
    }
    // Para valores pequenos (< 1), usar 4 casas decimais
    if (Math.abs(numValue) < 1) {
      return `$${numValue.toFixed(4)}`;
    }
    // Para valores maiores, usar 2 casas decimais
    return `$${numValue.toFixed(2)}`;
  };

  const formatPercentage = (value) => {
    // Percentuais permanecem visíveis
    if (value === null || value === undefined) return '0%';
    return `${value >= 0 ? '+' : ''}${value.toFixed(2)}%`;
  };

  const formatNumber = (value) => {
    if (hideValues) return '***';
    if (value === null || value === undefined) return '0';
    return new Intl.NumberFormat('pt-BR').format(value);
  };

  const getColorByValue = (value) => {
    if (value > 0) return theme.palette.success.main;
    if (value < 0) return theme.palette.error.main;
    return theme.palette.text.secondary;
  };

  const statsConfig = [
    {
      title: 'PnL Aberto',
      value: stats?.unrealized_pnl,
      format: formatCurrency,
      icon: AccountBalance,
      color: getColorByValue(stats?.unrealized_pnl || 0),
      description: hideValues ? '*** operações abertas' : `${stats?.open_positions_count || 0} operações abertas`
    },
    {
      title: 'ROE Total Aberto',
      value: stats?.sum_open_roe_percentage,
      format: formatPercentage,
      icon: TrendingUp,
      color: getColorByValue(stats?.sum_open_roe_percentage || 0),
      description: hideValues ? '*** operações abertas' : `${stats?.open_positions_count || 0} ${ (stats?.open_positions_count || 0) === 1 ? 'operação aberta' : 'operações abertas'}`
    },
    {
      title: 'PnL Realizado',
      value: stats?.realized_pnl,
      format: formatCurrency,
      icon: Timeline,
      color: getColorByValue(stats?.realized_pnl || 0),
      description: 'Lucro/Prejuízo de trades fechados'
    },
    {
      title: 'ROE Médio',
      value: stats?.average_roe,
      format: formatPercentage,
      icon: Percent,
      color: getColorByValue(stats?.average_roe || 0),
      description: 'Retorno sobre investimento médio'
    },
    {
      title: 'Total de Trades',
      value: stats?.total_trades,
      format: formatNumber,
      icon: ShowChart,
      color: theme.palette.primary.main,
      description: 'Número total de operações fechadas'
    },
    {
      title: 'Taxa de Acerto',
      value: stats?.win_rate,
      format: formatPercentage,
      icon: TrendingDown,
      color: getColorByValue(stats?.win_rate || 0),
      description: 'Percentual de trades lucrativos'
    },
    {
      title: 'Saldo Operacional',
      value: stats?.operational_balance_usd,
      format: formatCurrency,
      icon: AccountBalance,
      color: getColorByValue(stats?.operational_balance_usd || 0),
      description: `Comissão Atual = ${stats?.commission_rate || 35}%`,
      secondaryValue: stats?.operational_balance,
      secondaryFormat: (value) => hideValues ? 'R$ ***' : `R$ ${(value || 0).toFixed(2)}`
    },
    {
      title: 'Recarregar Conta',
      value: null,
      format: () => '',
      icon: AccountBalance,
      color: theme.palette.primary.main,
      description: 'Plano recarregável sem assinatura',
      isRechargeCard: true,
      rechargeOptions: [
        { value: 'R$ 9', link: 'https://pay.hub.la/ekfJp2uXQ0S5ZBb65Otb', isTest: true },
        { value: 'R$ 50', link: 'https://pay.hub.la/MdORdaFcTzWvhT9IkZHP' },
        { value: 'R$ 100', link: 'https://pay.hub.la/mFfwQbUAqILTw8bfDXjo' },
        { value: 'R$ 200', link: 'https://pay.hub.la/EVrxnuDyf4JeB0uIYaFC' },
        { value: 'R$ 500', link: 'https://pay.hub.la/LmFhy6R6HP3fjoJxZe5z' }
      ]
    }
  ];

  if (loading) {
    return (
      <Grid container spacing={3}>
        {Array.from({ length: 6 }).map((_, index) => (
          <Grid item xs={12} sm={6} md={4} lg={2} key={index}>
            <Card sx={{ height: '100%' }}>
              <CardContent>
                <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                  <Skeleton variant="circular" width={40} height={40} sx={{ mr: 2 }} />
                  <Box sx={{ flexGrow: 1 }}>
                    <Skeleton variant="text" width="60%" />
                    <Skeleton variant="text" width="40%" />
                  </Box>
                </Box>
                <Skeleton variant="text" width="80%" height={32} />
                <Skeleton variant="text" width="60%" />
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>
    );
  }

  return (
    <Grid container spacing={3}>
      {statsConfig.map((stat, index) => {
        const IconComponent = stat.icon;

        return (
          <Grid item xs={12} sm={6} md={4} lg={2} key={index}>
            <Card
              sx={{
                height: '100%',
                transition: 'all 0.3s ease',
                '&:hover': {
                  transform: 'translateY(-4px)',
                  boxShadow: theme.shadows[8]
                }
              }}
            >
              <CardContent>
                <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                  <Box
                    sx={{
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      width: 40,
                      height: 40,
                      borderRadius: '50%',
                      bgcolor: `${stat.color}20`,
                      mr: 2
                    }}
                  >
                    <IconComponent sx={{ color: stat.color, fontSize: 20 }} />
                  </Box>
                  <Box sx={{ flexGrow: 1 }}>
                    <Typography
                      variant="caption"
                      color="text.secondary"
                      sx={{ fontWeight: 500 }}
                    >
                      {stat.title}
                    </Typography>
                  </Box>
                </Box>

                {stat.isRechargeCard ? (
                  <>
                    <Box sx={{ mb: 2 }}>
                      <Typography
                        variant="caption"
                        color="text.secondary"
                        sx={{
                          display: 'block',
                          lineHeight: 1.2
                        }}
                      >
                        {stat.description}
                      </Typography>
                    </Box>

                    <Grid container spacing={1}>
                      {stat.rechargeOptions.map((option, optionIndex) => (
                        <Grid item xs={option.isTest ? 12 : 6} key={optionIndex}>
                          <Box
                            component="a"
                            href={option.link}
                            target="_blank"
                            rel="noopener noreferrer"
                            sx={{
                              display: 'flex',
                              alignItems: 'center',
                              justifyContent: 'center',
                              p: 1,
                              border: option.isTest 
                                ? `2px solid ${theme.palette.warning.main}` 
                                : `1px solid ${theme.palette.primary.main}`,
                              borderRadius: 1,
                              textDecoration: 'none',
                              color: option.isTest 
                                ? theme.palette.warning.main 
                                : theme.palette.primary.main,
                              fontSize: '0.875rem',
                              fontWeight: 'bold',
                              transition: 'all 0.2s ease',
                              bgcolor: option.isTest 
                                ? `${theme.palette.warning.main}10` 
                                : 'transparent',
                              '&:hover': {
                                bgcolor: option.isTest 
                                  ? theme.palette.warning.main 
                                  : theme.palette.primary.main,
                                color: 'white'
                              }
                            }}
                          >
                            {option.isTest ? `🧪 ${option.value} (TESTE)` : option.value}
                          </Box>
                        </Grid>
                      ))}
                    </Grid>
                  </>
                ) : (
                  <>
                    <Typography
                      variant="h5"
                      sx={{
                        fontWeight: 'bold',
                        color: stat.color,
                        mb: 1,
                        fontSize: { xs: '1.25rem', sm: '1.5rem' }
                      }}
                    >
                      {stat.format(stat.value)}
                    </Typography>

                    {stat.secondaryValue !== undefined && stat.secondaryFormat && (
                      <Typography
                        variant="body2"
                        color="text.secondary"
                        sx={{
                          fontWeight: 'medium',
                          mb: 0.5
                        }}
                      >
                        {stat.secondaryFormat(stat.secondaryValue)}
                      </Typography>
                    )}

                    <Typography
                      variant="caption"
                      color="text.secondary"
                      sx={{
                        display: 'block',
                        lineHeight: 1.2
                      }}
                    >
                      {stat.description}
                    </Typography>
                  </>
                )}
              </CardContent>
            </Card>
          </Grid>
        );
      })}
    </Grid>
  );
};

export default StatsCards;
